// ===== Optionbar.js =====
import React, { useState } from 'react';
import './Optionbar.css';
import {
    segmentOptions,
    highlightOptions,
    seasonOptions,
    locationOptions
} from './Icons/optionbarOptions';

// Grouped option arrays with titles
const optionCategories = [
    { key: 'segments', title: 'Segments', options: segmentOptions },
    { key: 'highlights', title: 'Highlights', options: highlightOptions },
    { key: 'seasons', title: 'Seasons', options: seasonOptions },
    { key: 'locations', title: 'Location Produced', options: locationOptions }
];

export default function Optionbar() {
    // Internal filter state: all options checked by default
    const initialFilters = optionCategories.reduce((acc, grp) => {
        acc[grp.key] = new Set(grp.options.map(o => o.id));
        return acc;
    }, {});

    const [filters, setFilters] = useState(initialFilters);

    const toggleOption = (groupKey, id) => {
        const newFilters = {
            segments: new Set(filters.segments),
            highlights: new Set(filters.highlights),
            seasons: new Set(filters.seasons),
            locations: new Set(filters.locations)
        };
        if (newFilters[groupKey].has(id)) newFilters[groupKey].delete(id);
        else newFilters[groupKey].add(id);
        setFilters(newFilters);
    };

    // Build list of selected filters for display
    const selectedList = Object.entries(filters).flatMap(([groupKey, set]) => {
        const group = optionCategories.find(g => g.key === groupKey);
        return Array.from(set).map(id => {
            const opt = group.options.find(o => o.id === id);
            return `${group.title}: ${opt?.label}`;
        });
    });

    return (
        <nav className="optionbar-container">
            <h3 className="optionbar-title">Filters & Categories</h3>
            <div className="optionbar-scrollable">
                {optionCategories.map((grp, idx) => (
                    <div key={grp.key} className="optionbar-group">
                        {idx > 0 && <hr className="optionbar-divider" />}
                        <h4 className="optionbar-group-title">{grp.title}</h4>
                        <ul className="optionbar-list">
                            {grp.options.map(opt => (
                                <li key={opt.id} className="option-item">
                                    <input
                                        type="checkbox"
                                        id={`${grp.key}-${opt.id}`}
                                        checked={filters[grp.key].has(opt.id)}
                                        onChange={() => toggleOption(grp.key, opt.id)}
                                    />
                                    <label htmlFor={`${grp.key}-${opt.id}`} className="option-label">
                                        <img src={opt.icon} alt={opt.label} className="option-icon" />
                                        {opt.label}
                                    </label>
                                </li>
                            ))}
                        </ul>
                    </div>
                ))}
            </div>
            <div className="optionbar-selected">
                <h4>Selected Filters:</h4>
                {selectedList.length > 0 ? (
                    <ul>
                        {selectedList.map((label, idx) => (
                            <li key={idx}>{label}</li>
                        ))}
                    </ul>
                ) : (
                    <p>None</p>
                )}
            </div>
        </nav>
    );
}
